Add retry_git_command() helper to crates/swarm-agents/src/worktree_bridge.rs for transient git failures.

Git operations fail transiently with 'index.lock' errors under concurrent access. Currently all git commands fail immediately.

ADD helper function:
fn retry_git_command(cmd: &mut Command, max_retries: u32) -> Result<Output> {
    let delays = [100, 500, 2000]; // ms
    for attempt in 0..=max_retries {
        let output = cmd.output()?;
        if output.status.success() { return Ok(output); }
        let stderr = String::from_utf8_lossy(&output.stderr);
        if attempt < max_retries && (stderr.contains("index.lock") || stderr.contains("Unable to create")) {
            std::thread::sleep(Duration::from_millis(delays[attempt as usize]));
            continue;
        }
        return Ok(output); // return the failure for caller to handle
    }
}

